-- =====================================================================
-- Seed data (~5 sample rows per table) for TutorConnectSystem (TCS)
-- Inserted in FK-dependency order. UUIDs use a per-table prefix + row no.
-- NOTE:
--   * `role` has only 4 rows (role_name CHECK allows exactly 4 unique values).
--   * For sample purposes the same 5 users are reused across the profile
--     tables (client/tutor/tutor_center/platform_admin) and wallet; this is
--     allowed because each UNIQUE(user_id) is scoped per table.
-- =====================================================================

SET NAMES utf8mb4;

-- ---------------------------------------------------------------------
-- Role (4 rows only)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Province
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Grade
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Subject
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- User (ref role)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Location (ref province)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Client (ref user, location)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Tutor (ref user, location)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- TutorCenter (ref user, location)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- PlatformAdmin (ref user)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Wallet (ref user)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- PaymentMethod (ref wallet)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- TutorSubject (ref tutor, subject)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Qualification (ref tutor)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- VerificationRequest (ref user)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- VerificationDocument (ref verification_request)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- VerificationHistory (ref verification_request, user)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Class (ref user, subject, location, grade)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- TutorApplication (ref class, tutor)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- ApplicationStatusHistory (ref tutor_application, user)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- ClassAssignment (ref tutor_application)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Lesson (ref class, user)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- Payment (ref user, payment_method)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- PaymentHistory (ref payment, user)
-- ---------------------------------------------------------------------

-- ---------------------------------------------------------------------
-- EscrowTransaction (ref payment, class_assignment)
